update sb_menu
menu_name = #{menuName}, parent_id = #{parentId}, order_num = #{orderNum}, path = #{path}, component = #{component}, is_frame = #{isFrame}, is_cache = #{isCache}, menu_type = #{menuType}, visible = #{visible}, status = #{status}, perms = #{perms}, icon = #{icon}, remark = #{remark}, default_open_to_customer = #{defaultOpenToCustomer}, update_by = #{updateBy}, update_time = sysdate()
where menu_id = #{menuId}
